// MARK: - Network Configuration

enum NetworkEnvironment {
    case cloud
    case localDevice
    
    var baseURL: String {
        switch self {
        case .cloud:
            return "https://api.example.com"
        case .localDevice:
            return "" // Set dynamically per device
        }
    }
}

struct DeviceEndpoint {
    let host: String // e.g., "192.168.1.100"
    let port: Int
    let useTLS: Bool
    
    var baseURL: String {
        let scheme = useTLS ? "https" : "http"
        return "\(scheme)://\(host):\(port)"
    }
}

// MARK: - Custom Session Delegate for Local Device Certificate Handling

final class IoTSessionDelegate: NSObject, URLSessionDelegate, URLSessionTaskDelegate {
    
    /// Set of trusted local network prefixes
    private let trustedLocalPrefixes = ["192.168.", "10.", "172.16.", "172.17.", "172.18.",
                                         "172.19.", "172.20.", "172.21.", "172.22.", "172.23.",
                                         "172.24.", "172.25.", "172.26.", "172.27.", "172.28.",
                                         "172.29.", "172.30.", "172.31."]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let host = Optional(challenge.protectionSpace.host) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // For cloud API: perform standard TLS validation
        if !isLocalNetworkHost(host) {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // For local IoT devices with self-signed certs: accept if on local network
        // This is scoped ONLY to local network addresses
        if isLocalNetworkHost(host) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
            return
        }
        
        completionHandler(.cancelAuthenticationChallenge, nil)
    }
    
    private func isLocalNetworkHost(_ host: String) -> Bool {
        return trustedLocalPrefixes.contains(where: { host.hasPrefix($0) }) || host == "localhost" || host == "127.0.0.1"
    }
}

// MARK: - HTTP Client

final class HTTPClient {
    
    static let shared = HTTPClient()
    
    // Session for cloud API calls — standard TLS, no custom delegate
    private let cloudSession: URLSession
    
    // Session for local IoT devices — custom delegate for self-signed certs
    private let localSession: URLSession
    
    private let iotDelegate = IoTSessionDelegate()
    
    private let jsonDecoder: JSONDecoder = {
        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        decoder.dateDecodingStrategy = .iso8601
        return decoder
    }()
    
    private let jsonEncoder: JSONEncoder = {
        let encoder = JSONEncoder()
        encoder.keyEncodingStrategy = .convertToSnakeCase
        encoder.dateEncodingStrategy = .iso8601
        return encoder
    }()
    
    private init() {
        // Cloud session: strict TLS, connection pooling, standard timeouts
        let cloudConfig = URLSessionConfiguration.default
        cloudConfig.tlsMinimumSupportedProtocolVersion = .TLSv12
        cloudConfig.timeoutIntervalForRequest = 30
        cloudConfig.timeoutIntervalForResource = 60
        cloudConfig.waitsForConnectivity = true
        cloudConfig.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        self.cloudSession = URLSession(configuration: cloudConfig)
        
        // Local session: relaxed for IoT devices, shorter timeouts
        let localConfig = URLSessionConfiguration.default
        localConfig.timeoutIntervalForRequest = 10
        localConfig.timeoutIntervalForResource = 20
        localConfig.waitsForConnectivity = false
        localConfig.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        self.localSession = URLSession(
            configuration: localConfig,
            delegate: iotDelegate,
            delegateQueue: nil
        )
    }
    
    // MARK: - Request Building
    
    enum HTTPMethod: String {
        case GET, POST, PUT, PATCH, DELETE
    }
    
    struct RequestConfig {
        let path: String
        let method: HTTPMethod
        let headers: [String: String]?
        let queryItems: [URLQueryItem]?
        let body: Data?
        let environment: NetworkEnvironment
        let deviceEndpoint: DeviceEndpoint?
        
        init(
            path: String,
            method: HTTPMethod = .GET,
            headers: [String: String]? = nil,
            queryItems: [URLQueryItem]? = nil,
            body: Data? = nil,
            environment: NetworkEnvironment = .cloud,
            deviceEndpoint: DeviceEndpoint? = nil
        ) {
            self.path = path
            self.method = method
            self.headers = headers
            self.queryItems = queryItems
            self.body = body
            self.environment = environment
            self.deviceEndpoint = deviceEndpoint
        }
    }
    
    private func buildRequest(from config: RequestConfig) throws -> URLRequest {
        let baseURL: String
        switch config.environment {
        case .cloud:
            baseURL = NetworkEnvironment.cloud.baseURL
        case .localDevice:
            guard let endpoint = config.deviceEndpoint else {
                throw HTTPClientError.missingDeviceEndpoint
            }
            baseURL = endpoint.baseURL
        }
        
        guard var components = URLComponents(string: baseURL + config.path) else {
            throw HTTPClientError.invalidURL(baseURL + config.path)
        }
        
        if let queryItems = config.queryItems {
            components.queryItems = queryItems
        }
        
        guard let url = components.url else {
            throw HTTPClientError.invalidURL(components.string ?? "unknown")
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = config.method.rawValue
        request.httpBody = config.body
        
        config.headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        return request
    }
    
    // MARK: - Request Execution
    
    func request<T: Decodable>(
        _ config: RequestConfig,
        responseType: T.Type
    ) async throws -> T {
        let urlRequest = try buildRequest(from: config)
        let session = sessionForEnvironment(config.environment)
        
        let (data, response) = try await session.data(for: urlRequest)
        
        try validateResponse(response, data: data)
        
        do {
            let decoded = try jsonDecoder.decode(T.self, from: data)
            return decoded
        } catch {
            throw HTTPClientError.decodingFailed(error)
        }
    }
    
    func requestRaw(_ config: RequestConfig) async throws -> (Data, HTTPURLResponse) {
        let urlRequest = try buildRequest(from: config)
        let session = sessionForEnvironment(config.environment)
        
        let (data, response) = try await session.data(for: urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw HTTPClientError.invalidResponse
        }
        
        return (data, httpResponse)
    }
    
    func send<T: Encodable, R: Decodable>(
        _ config: RequestConfig,
        body: T,
        responseType: R.Type
    ) async throws -> R {
        let bodyData = try jsonEncoder.encode(body)
        let updatedConfig = RequestConfig(
            path: config.path,
            method: config.method,
            headers: config.headers,
            queryItems: config.queryItems,
            body: bodyData,
            environment: config.environment,
            deviceEndpoint: config.deviceEndpoint
        )
        return try await request(updatedConfig, responseType: R.self)
    }
    
    // MARK: - Helpers
    
    private func sessionForEnvironment(_ environment: NetworkEnvironment) -> URLSession {
        switch environment {
        case .cloud:
            return cloudSession
        case .localDevice:
            return localSession
        }
    }
    
    private func validateResponse(_ response: URLResponse, data: Data) throws {
        guard let httpResponse = response as? HTTPURLResponse else {
            throw HTTPClientError.invalidResponse
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            return
        case 401:
            throw HTTPClientError.unauthorized
        case 403:
            throw HTTPClientError.forbidden
        case 404:
            throw HTTPClientError.notFound
        case 429:
            let retryAfter = httpResponse.value(forHTTPHeaderField: "Retry-After")
            throw HTTPClientError.rateLimited(retryAfter: retryAfter)
        case 500...599:
            throw HTTPClientError.serverError(statusCode: httpResponse.statusCode, data: data)
        default:
            throw HTTPClientError.httpError(statusCode: httpResponse.statusCode, data: data)
        }
    }
}

// MARK: - Errors

enum HTTPClientError: LocalizedError {
    case invalidURL(String)
    case invalidResponse
    case missingDeviceEndpoint
    case unauthorized
    case forbidden
    case notFound
    case rateLimited(retryAfter: String?)
    case serverError(statusCode: Int, data: Data)
    case httpError(statusCode: Int, data: Data)
    case decodingFailed(Error)
    case deviceUnreachable(String)
    
    var errorDescription: String? {
        switch self {
        case .invalidURL(let url):
            return "Invalid URL: \(url)"
        case .invalidResponse:
            return "Invalid response from server"
        case .missingDeviceEndpoint:
            return "Device endpoint is required for local network requests"
        case .unauthorized:
            return "Authentication required (401)"
        case .forbidden:
            return "Access forbidden (403)"
        case .notFound:
            return "Resource not found (404)"
        case .rateLimited(let retryAfter):
            return "Rate limited. Retry after: \(retryAfter ?? "unknown")"
        case .serverError(let code, _):
            return "Server error (\(code))"
        case .httpError(let code, _):
            return "HTTP error (\(code))"
        case .decodingFailed(let error):
            return "Decoding failed: \(error.localizedDescription)"
        case .deviceUnreachable(let host):
            return "Device unreachable: \(host)"
        }
    }
}

// MARK: - IoT Device Manager

final class IoTDeviceManager {
    
    private let client = HTTPClient.shared
    
    struct DeviceInfo: Codable {
        let id: String
        let name: String
        let firmwareVersion: String
        let status: String
    }
    
    struct DeviceCommand: Codable {
        let action: String
        let parameters: [String: String]?
    }
    
    struct DeviceResponse: Codable {
        let success: Bool
        let message: String?
    }
    
    /// Discover and get info from a local IoT device
    func getDeviceInfo(endpoint: DeviceEndpoint) async throws -> DeviceInfo {
        let config = HTTPClient.RequestConfig(
            path: "/api/device/info",
            method: .GET,
            environment: .localDevice,
            deviceEndpoint: endpoint
        )
        return try await client.request(config, responseType: DeviceInfo.self)
    }
    
    /// Send a command to a local IoT device
    func sendCommand(_ command: DeviceCommand, to endpoint: DeviceEndpoint) async throws -> DeviceResponse {
        let config = HTTPClient.RequestConfig(
            path: "/api/device/command",
            method: .POST,
            environment: .localDevice,
            deviceEndpoint: endpoint
        )
        return try await client.send(config, body: command, responseType: DeviceResponse.self)
    }
    
    /// Check if a device is reachable
    func pingDevice(endpoint: DeviceEndpoint) async -> Bool {
        let config = HTTPClient.RequestConfig(
            path: "/api/ping",
            method: .GET,
            environment: .localDevice,
            deviceEndpoint: endpoint
        )
        do {
            let (_, response) = try await client.requestRaw(config)
            return response.statusCode == 200
        } catch {
            return false
        }
    }
}

// MARK: - Cloud API Service

final class CloudAPIService {
    
    private let client = HTTPClient.shared
    private var authToken: String?
    
    struct AuthResponse: Codable {
        let token: String
        let expiresIn: Int
    }
    
    struct DeviceRegistration: Codable {
        let deviceId: String
        let deviceName: String
        let localIp: String
    }
    
    struct CloudDeviceList: Codable {
        let devices: [RegisteredDevice]
    }
    
    struct RegisteredDevice: Codable {
        let id: String
        let name: String
        let localIp: String
        let lastSeen: Date?
        let isOnline: Bool
    }
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    private var authHeaders: [String: String]? {
        guard let token = authToken else { return nil }
        return ["Authorization": "Bearer \(token)"]
    }
    
    /// Authenticate with the cloud API
    func authenticate(username: String, password: String) async throws -> AuthResponse {
        struct LoginBody: Codable {
            let username: String
            let password: String
        }
        
        let config = HTTPClient.RequestConfig(
            path: "/v1/auth/login",
            method: .POST,
            environment: .cloud
        )
        
        let response = try await client.send(
            config,
            body: LoginBody(username: username, password: password),
            responseType: AuthResponse.self
        )
        
        self.authToken = response.token
        return response
    }
    
    /// Register a local device with the cloud
    func registerDevice(_ registration: DeviceRegistration) async throws -> RegisteredDevice {
        let config = HTTPClient.RequestConfig(
            path: "/v1/devices",
            method: .POST,
            headers: authHeaders,
            environment: .cloud
        )
        return try await client.send(config, body: registration, responseType: RegisteredDevice.self)
    }
    
    /// Get all registered devices
    func getDevices() async throws -> [RegisteredDevice] {
        let config = HTTPClient.RequestConfig(
            path: "/v1/devices",
            method: .GET,
            headers: authHeaders,
            environment: .cloud
        )
        let list = try await client.request(config, responseType: CloudDeviceList.self)
        return list.devices
    }
    
    /// Report device telemetry to the cloud
    func reportTelemetry(deviceId: String, data: [String: String]) async throws {
        struct TelemetryPayload: Codable {
            let deviceId: String
            let data: [String: String]
            let timestamp: Date
        }
        
        let config = HTTPClient.RequestConfig(
            path: "/v1/devices/\(deviceId)/telemetry",
            method: .POST,
            headers: authHeaders,
            environment: .cloud
        )
        
        let payload = TelemetryPayload(deviceId: deviceId, data: data, timestamp: Date())
        let _ = try await client.send(config, body: payload, responseType: CloudAPIService.EmptyResponse.self)
    }
    
    private struct EmptyResponse: Codable {}
}

// MARK: - Usage Example

@MainActor
final class DeviceViewController {
    
    private let deviceManager = IoTDeviceManager()
    private let cloudService = CloudAPIService()
    
    func demonstrateUsage() async {
        // 1. Authenticate with cloud API (HTTPS)
        do {
            let auth = try await cloudService.authenticate(
                username: "admin",
                password: "securePassword123"
            )
            print("Authenticated. Token expires in \(auth.expiresIn)s")
        } catch {
            print("Cloud auth failed: \(error.localizedDescription)")
            return
        }
        
        // 2. Connect to a local IoT device (HTTP — legacy device)
        let legacyDevice = DeviceEndpoint(
            host: "192.168.1.100",
            port: 80,
            useTLS: false
        )
        
        // 3. Connect to a newer local IoT device (HTTPS with self-signed cert)
        let modernDevice = DeviceEndpoint(
            host: "192.168.1.101",
            port: 443,
            useTLS: true
        )
        
        // 4. Ping devices
        let legacyReachable = await deviceManager.pingDevice(endpoint: legacyDevice)
        let modernReachable = await deviceManager.pingDevice(endpoint: modernDevice)
        print("Legacy device reachable: \(legacyReachable)")
        print("Modern device reachable: \(modernReachable)")
        
        // 5. Get device info from local device
        do {
            let info = try await deviceManager.getDeviceInfo(endpoint: legacyDevice)
            print("Device: \(info.name), FW: \(info.firmwareVersion)")
            
            // 6. Register device with cloud
            let registration = CloudAPIService.DeviceRegistration(
                deviceId: info.id,
                deviceName: info.name,
                localIp: legacyDevice.host
            )
            let registered = try await cloudService.registerDevice(registration)
            print("Registered device: \(registered.id)")
            
        } catch {
            print("Device operation failed: \(error.localizedDescription)")
        }
        
        // 7. Send command to local device
        do {
            let command = IoTDeviceManager.DeviceCommand(
                action: "toggle",
                parameters: ["target": "relay1", "state": "on"]
            )
            let response = try await deviceManager.sendCommand(command, to: modernDevice)
            print("Command result: \(response.success) - \(response.message ?? "")")
        } catch {
            print("Command failed: \(error.localizedDescription)")
        }
        
        // 8. Fetch all devices from cloud
        do {
            let devices = try await cloudService.getDevices()
            for device in devices {
                print("Cloud device: \(device.name) at \(device.localIp) - online: \(device.isOnline)")
            }
        } catch {
            print("Failed to fetch devices: \(error.localizedDescription)")
        }
    }
}